import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import PredictionForm from './components/PredictionForm';
import ResultsDisplay from './components/ResultsDisplay';
import Dashboard from './components/Dashboard';
import WeatherWidget from './components/WeatherWidget';

function App() {
  const [activeTab, setActiveTab] = useState('predict');
  const [predictionResult, setPredictionResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [language, setLanguage] = useState('en');

  const handlePrediction = async (formData) => {
    setLoading(true);
    try {
      const response = await axios.post('http://localhost:5000/api/predict', formData);
      setPredictionResult(response.data);
      setActiveTab('results');
    } catch (error) {
      console.error('Prediction error:', error);
      alert('Error making prediction. Please check your inputs or ensure the backend is running.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <div className="header-content" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', maxWidth: '1400px', margin: '0 auto', width: '100%' }}>
          <div className="logo-section" style={{ textAlign: 'left' }}>
            <h1 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <span style={{ fontSize: '2.5rem' }}>🌾</span>
              <span>AI-Powered Crop Yield Prediction</span>
            </h1>
            <p>Smart Farming Solutions for Indian Farmers</p>
          </div>

          <div className="language-selector" style={{ background: '#f7fafc', padding: '0.5rem', borderRadius: '8px', border: '1px solid #e2e8f0' }}>
            <select
              value={language}
              onChange={(e) => setLanguage(e.target.value)}
              style={{ background: 'transparent', border: 'none', outline: 'none', fontWeight: 600, color: '#4a5568', cursor: 'pointer' }}
            >
              <option value="en">English (EN)</option>
              <option value="or">ଓଡ଼ିଆ (OR)</option>
              <option value="hi">हिंदी (HI)</option>
            </select>
          </div>
        </div>
      </header>

      <nav className="nav-tabs">
        <button
          className={activeTab === 'dashboard' ? 'active' : ''}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
        <button
          className={activeTab === 'predict' ? 'active' : ''}
          onClick={() => setActiveTab('predict')}
        >
          🔮 Predict Yield
        </button>
        <button
          className={activeTab === 'results' ? 'active' : ''}
          onClick={() => setActiveTab('results')}
          disabled={!predictionResult}
        >
          📋 Results
        </button>
      </nav>

      <div className="content-container">
        <div className="main-content">
          {activeTab === 'dashboard' && (
            <Dashboard />
          )}

          {activeTab === 'predict' && (
            <PredictionForm
              onSubmit={handlePrediction}
              loading={loading}
              selectedLanguage={language}
            />
          )}

          {activeTab === 'results' && predictionResult && (
            <ResultsDisplay
              result={predictionResult}
            />
          )}
        </div>

        <div className="sidebar">
          <WeatherWidget />
        </div>
      </div>

      <footer className="App-footer">
        <p>© 2026 Crop Yield AI Platform | Government of Odisha Initiative</p>
        <p>Empowering farmers with data-driven insights</p>
      </footer>
    </div>
  );
}

export default App;
